CREATE DEFINER=`root`@`localhost` FUNCTION `keyword_search`(filter VARCHAR(255)) RETURNS varchar(4000) CHARSET utf8mb4
    DETERMINISTIC
BEGIN
    DECLARE escaped_filter VARCHAR(255);
    SET escaped_filter = REPLACE(REPLACE(REPLACE(filter, '\\', '\\\\'), '_', '\\_'), '%', '\\%');
    
    RETURN CONCAT(
        'SELECT * FROM csl.helps ',
        'WHERE keywords REGEXP ? ',
        'AND keywords NOT REGEXP ?'
    );
END ;;
