CREATE DEFINER=`root`@`localhost` PROCEDURE `execute_keyword_search`(IN filter VARCHAR(255))
BEGIN
    SET @query = keyword_search(filter);
    SET @regex_pattern = CONCAT('(^|[[:space:]])(''', filter, '[^'']*''|', filter, '[^[[:space:]]|$]*([[:space:]]|$))');
    SET @exclude_pattern = CONCAT('''[^'']*[[:space:]]', filter, '[^'']*''');
    
    PREPARE stmt FROM @query;
    EXECUTE stmt USING @regex_pattern, @exclude_pattern;
    DEALLOCATE PREPARE stmt;
END ;;
